import java.io.*;

public class SecureXSSDemo {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userName = reader.readLine();

            // Sanitize and escape user input to prevent XSS
            userName = sanitizeInput(userName);

            System.out.println("Hello, " + userName + "!"); // Safe output

        } catch (IOException e) {
            System.err.println("Error reading input!");
        }
    }

    // Function to sanitize and escape user input to prevent XSS
    private static String sanitizeInput(String input) {
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("&", "&amp;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
